CREATE PROC [dbo].[TR_DINHMUC_SON_Update2]
( 
	@id       nvarchar(50), 
	@pcode    nvarchar(50), 
	@ccode    nvarchar(50), 
	@c_level  int, 
	@stt      nvarchar(50), 
	@buoc     nvarchar(200), 
	@mact     nvarchar(200), 
	@tenct    nvarchar(max), 
	@m2       decimal(18, 5), 
	@sl_m2    decimal(18, 5), 
	--@sl_sp    nvarchar(50), 
	@dvt      nvarchar(50), 
	@ghichu   nvarchar(max), 
	@sontrongsanpham bit = 0,
	@nguoisua nvarchar(50)
)
AS
BEGIN
    UPDATE tr_dinhmuc_son
	 SET  pcode = @pcode, 
		 ccode = @ccode, 
		 c_level = @c_level,
		 stt = @stt, 
		 buoc = @buoc, 
		 mact = @mact, 
		 tenct = @tenct, 
		 m2 = @m2, 
		 sl_m2 = @sl_m2, 
		 sl_sp = @m2 * @sl_m2, 
		 dvt = @dvt, 
		 ghichu = @ghichu, 
		 sontrongsanpham = @sontrongsanpham,
		 nguoisua = @nguoisua, 
		 ngaysua = GETDATE()
    WHERE  id = @id
